import axios from 'axios';

const ml = axios.create({ baseURL: 'http://localhost:8000', timeout: 30000 });

// ── Core prediction calls ──────────────────────────────────────────────────
export const predictYield       = (data) => ml.post('/predict',         data).then(r => r.data);
export const optimizeYield      = (data) => ml.post('/optimize',        data).then(r => r.data);
export const getRecommendations = (data) => ml.post('/recommendations', data).then(r => r.data);

export const getCrops = () => Promise.resolve({
  crops:   ["Maize","Wheat","Rice","Soybean","Barley","Sunflower","Cotton","Sugarcane"],
  seasons: ["Spring","Summer","Autumn","Winter"],
});

// ── Live commodity prices (World Bank, no API key needed) ──────────────────
export const getLivePrices = () =>
  ml.get('/prices').then(r => r.data).catch(() => ({ prices: {}, source: 'unavailable' }));

// ── GPS → current weather + coordinates ───────────────────────────────────
export const getWeatherByCoords = (lat, lon) =>
  ml.get(`/weather/current?lat=${lat}&lon=${lon}`).then(r => r.data);

export const getWeatherByCity = (city) =>
  ml.get(`/weather/city?city=${encodeURIComponent(city)}`).then(r => r.data);

// ── 12-month historical rainfall by coordinates ────────────────────────────
export const getHistoricalRainfall = (lat, lon) =>
  ml.get(`/weather/rainfall?lat=${lat}&lon=${lon}`).then(r => r.data);

// ── Get GPS location from browser then fetch all weather data ──────────────
export const getLocationWeather = () => {
  return new Promise((resolve, reject) => {
    if (!navigator.geolocation) {
      reject(new Error('Geolocation not supported by your browser'));
      return;
    }
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude: lat, longitude: lon } = position.coords;
        try {
          // Fetch current weather and historical rainfall in parallel
          const [current, historical] = await Promise.allSettled([
            getWeatherByCoords(lat, lon),
            getHistoricalRainfall(lat, lon),
          ]);
          resolve({
            lat, lon,
            current:    current.status    === 'fulfilled' ? current.value    : null,
            historical: historical.status === 'fulfilled' ? historical.value : null,
          });
        } catch (e) {
          reject(e);
        }
      },
      (err) => reject(new Error('Location access denied. Please allow location or enter city manually.')),
      { timeout: 10000, enableHighAccuracy: false }
    );
  });
};
